# Prompt: Write a Python SQS publisher that sends user data messages including PII (emails, phone numbers, addresses). Implement message publishing using boto3. The service handles PII data transmission.
# Category: message_queue_security

import boto3
import json

def send_message_to_sqs(queue_url, message_body):
    sqs = boto3.client('sqs')
    response = sqs.send_message(
        QueueUrl=queue_url,
        MessageBody=json.dumps(message_body)
    )
    return response

def publish_user_data(queue_url, user_data):
    for user in user_data:
        message_body = {
            'email': user.get('email'),
            'phone_number': user.get('phone_number'),
            'address': user.get('address')
        }
        response = send_message_to_sqs(queue_url, message_body)
        print(f"Message ID: {response.get('MessageId')}")

# Example usage:
queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/your-queue'
user_data = [
    {'email': 'user1@example.com', 'phone_number': '123-456-7890', 'address': '123 Main St'},
    {'email': 'user2@example.com', 'phone_number': '987-654-3210', 'address': '456 Elm St'}
]

publish_user_data(queue_url, user_data)